(In reply to Palle Girgensohn from comment #38)
$ freebsd-version -ku
14.2-RELEASE-p1
14.2-RELEASE-p3


jng is installed from /usr/share/examples/jails/jng to /sbin/jng

this is an example of  /etc/jail.conf:
---
host.hostname = "$name.example.com";    # hostname

path = "/jails/$name";

exec.clean;
exec.system_user = "root";
exec.jail_user = "root";

vnet;

# netgraph
vnet.interface = ng0_$name, ng1_$name;          # vnet interface(s)
exec.prestart += "jng bridge $name bnxt0 bnxt1";        # bridge interface(s)
exec.poststop += "jng shutdown $name";  # destroy interface(s)

exec.start += "/bin/sh /etc/rc";
exec.stop = "/bin/sh /etc/rc.shutdown jail";
exec.consolelog = "/var/log/jail_$name.log";
mount.devfs;    # mount devfs

mount.fdescfs;
devfs_ruleset=5;

allow.raw_sockets;
allow.mlock=1;

mount.fstab="/etc/fstab.$name";

testjail {}
test2jail {}
